(function() {
  if (typeof window === 'undefined' || !window.electronAPI || !window.electronAPI.onUpdateAvailable) return;
  window.electronAPI.onUpdateAvailable(function(info) {
    if (document.getElementById('__update-banner__')) return;
    var banner = document.createElement('div');
    banner.id = '__update-banner__';
    banner.style.cssText = 'position:fixed;top:0;left:0;right:0;z-index:999999;display:flex;align-items:center;justify-content:center;gap:12px;padding:10px 20px;background:linear-gradient(90deg,#2d1a4e 0%,#1a0a3a 100%);box-shadow:0 2px 12px rgba(0,0,0,0.5);font-family:inherit;';
    var icon = document.createElement('span');
    icon.textContent = '⭐';
    icon.style.cssText = 'font-size:18px;color:#f0c040;flex-shrink:0;';
    var text = document.createElement('span');
    text.style.cssText = 'color:#f0f0ff;font-size:14px;font-weight:500;';
    text.textContent = 'Yeni sürüm mevcut: v' + info.version;
    var updateBtn = document.createElement('button');
    updateBtn.textContent = 'Güncelle';
    updateBtn.style.cssText = 'background:#7c3aed;color:#fff;border:none;border-radius:6px;padding:5px 14px;font-size:13px;font-weight:600;cursor:pointer;flex-shrink:0;transition:background 0.2s;';
    updateBtn.onmouseenter = function() { this.style.background = '#6d28d9'; };
    updateBtn.onmouseleave = function() { this.style.background = '#7c3aed'; };
    updateBtn.onclick = function() { window.electronAPI.openDownloadUrl(info.downloadUrl); };
    var closeBtn = document.createElement('button');
    closeBtn.textContent = '✕';
    closeBtn.style.cssText = 'background:transparent;color:#a0a0c0;border:none;font-size:16px;cursor:pointer;flex-shrink:0;padding:0 4px;line-height:1;';
    closeBtn.onmouseenter = function() { this.style.color = '#fff'; };
    closeBtn.onmouseleave = function() { this.style.color = '#a0a0c0'; };
    closeBtn.onclick = function() { banner.remove(); };
    banner.appendChild(icon);
    banner.appendChild(text);
    banner.appendChild(updateBtn);
    banner.appendChild(closeBtn);
    document.body.insertBefore(banner, document.body.firstChild);
  });
})();
